// Syntax:
condition ? valueIfTrue : valueIfFalse

// Example:
const isLoggedIn = true;
const message = isLoggedIn ? 'Welcome back!' : 'Please sign in';
console.log(message); // 'Welcome back!'

function Alert({ message }) {
  return (
    <div>
      {message ? <p className="alert">{message}</p> : null}
    </div>
  );
}

// Acceptable for 2 conditions:
function Status({ status }) {
  return (
    <span>
      {status === 'loading' ? 'Loading...'
        : status === 'error' ? 'Something went wrong'
        : 'Ready'}
    </span>
  );
}

// Better for 3+ conditions — extract to a variable:
function Status({ status }) {
  let label;
  if (status === 'loading') label = 'Loading...';
  else if (status === 'error') label = 'Something went wrong';
  else if (status === 'empty') label = 'No results';
  else label = 'Ready';

  return <span>{label}</span>;
}

function UserProfile({ user, isAdmin }) {
  return (
    <div>
      <h2>{user.name}</h2>

      {/* Only show admin panel if user is an admin */}
      {isAdmin && <AdminPanel />}

      {/* Only show notifications if there are any */}
      {user.notifications.length > 0 && (
        <NotificationBadge count={user.notifications.length} />
      )}
    </div>
  );
}

// ❌ When count is 0, renders the text '0' instead of nothing
function Cart({ count }) {
  return <div>{count && <Badge count={count} />}</div>;
  // If count === 0: renders <div>0</div> — you see '0' on screen
}

// ✅ Use a boolean comparison:
function Cart({ count }) {
  return <div>{count > 0 && <Badge count={count} />}</div>;
  // If count === 0: renders <div></div> — nothing shown
}

// ✅ Or convert to boolean with !!:
{!!count && <Badge count={count} />}

// Returns the first truthy value, or the last value if all are falsy
'hello' || 'world'  // 'hello' (left is truthy, short-circuits)
false || 'world'    // 'world' (left is falsy, returns right)
0 || 42             // 42      (left is falsy)
null || undefined   // undefined (both falsy, returns last)

// Common uses:
const name = inputName || 'Anonymous';
const port = process.env.PORT || 3000;

function Avatar({ src, fallbackSrc }) {
  // Use fallback if src is empty/null/undefined:
  const imageSrc = src || fallbackSrc;
  return <img src={imageSrc} alt="avatar" />;
}

function Username({ name }) {
  // Show 'Guest' if name is missing or empty:
  return <span>{name || 'Guest'}</span>;
}

// Score component where 0 is a valid score
function Score({ value }) {
  // ❌ || replaces 0 with 'N/A' — looks like no score when score is 0
  const display = value || 'N/A';

  // ✅ ?? only replaces when there is truly no value
  const display = value ?? 'N/A';

  return <span>{display}</span>;
}

const user = null;

// ❌ TypeError: Cannot read properties of null
console.log(user.profile.avatar);

// ✅ Returns undefined — no crash
console.log(user?.profile?.avatar); // undefined

// Combine with ?? for a clean default
console.log(user?.profile?.avatar ?? '/default-avatar.png');

// Works with method calls too
user?.updateProfile?.({ bio: 'hello' }); // only calls if user and updateProfile exist

function Profile({ user }) {
  // user might be null while data is loading
  return (
    <div>
      <img src={user?.avatar ?? '/default.png'} alt="avatar" />
      <h2>{user?.name ?? 'Loading...'}</h2>
      <p>{user?.bio}</p>
    </div>
  );
}
